  ('aboriginal-f0899a01-moex-00597', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-0f9358e7', 'sub-aboriginal-f0899a01-02', NULL, 'essay', '司法事務官及法官助理依法各得辦理之事務為何？試分別說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "26798cd33b5c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "法院組織法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
